// A runnable program starts at task main and leaves through exit.
task main() -> u32 {
    state start() {
        exit 42;
    }
}

// Functions are total helpers that tasks can call.
fn scale_then_add(left: u32, right: u32) -> u32 {
    left * right or(err) 0
}

task main() -> u32 {
    state start() {
        exit scale_then_add(6, 7);
    }
}

// let introduces bindings, mut allows assignment, and blocks produce values.
task main() -> u32 {
    state start() {
        let start: u32 = 10;
        let mut total: u32 = start;

        total = {
            let bonus: u32 = 32;
            total + bonus or(err) 0
        };

        exit total;
    }
}

// read_u32 consumes one token from the playground stdin field.
task main() -> u32 {
    state start() {
        let value: u32 = read_u32();
        unsafe { Structural::use(value); }
        let doubled: u32 = value * 2 or(err) 0;

        print_u32(doubled);
        print_newline();
        print_bool(doubled > value);
        print_newline();

        exit doubled;
    }
}

// if is a statement and conditions are bool values.
task main() -> u32 {
    state start() {
        let value: u32 = 42;

        if (value > 10 && value < 100) || value == 7 {
            exit value;
        }

        exit 0;
    }
}

// match supports literal, wildcard, and binding patterns.
fn choose(flag: bool, code: u32) -> u32 {
    let mut value: u32 = 0;

    match flag {
        true => { value = 10; },
        false => { value = 20; }
    }

    match code {
        0 => { value = value + 1 or(err) 0; },
        7 => { value = value + 32 or(err) 0; },
        _ => { value = value + code or(err) 0; }
    }

    value
}

task main() -> u32 {
    state start() {
        exit choose(true, 7);
    }
}

// Ordinary u32 arithmetic returns Result<u32, ArithmeticError>.
task main() -> u32 {
    state start() {
        let added: u32 = 40 + 2 or(err) 0;
        let subtracted: u32 = 50 - 8 or(err) 0;
        let multiplied: u32 = 6 * 7 or(err) 0;
        let divided: u32 = 84 / 2 or(err) 0;
        let remainder: u32 = 85 % 43 or(err) 0;
        let mut failures: u32 = 0;

        let _ = 4294967295 + 1 or(err) {
            if err == arithmetic_overflow() {
                failures = failures + 1 or(err) 0;
            }
            0
        };

        let _ = 0 - 1 or(err) {
            if err == arithmetic_underflow() {
                failures = failures + 1 or(err) 0;
            }
            0
        };

        let _ = 1 / 0 or(err) {
            if err == divide_by_zero() {
                failures = failures + 1 or(err) 0;
            }
            0
        };

        let _ = 1 % 0 or(err) {
            if err == remainder_by_zero() {
                failures = failures + 1 or(err) 0;
            }
            0
        };

        if added == 42 && subtracted == 42 && multiplied == 42 && divided == 42 && remainder == 42 && failures == 4 {
            exit 42;
        }

        exit 0;
    }
}

// Option<T> is either some(value) or none().
task main() -> u32 {
    state start() {
        let present: Option<u32> = some(40);
        let missing: Option<u32> = none();
        let left: u32 = present or 0;
        let right: u32 = missing or 2;
        exit left + right or(err) 0;
    }
}

// Result recovery can bind the error payload.
fn parse_like(flag: bool) -> Result<u32, bool> {
    if flag {
        return ok(40);
    }

    err(true)
}

task main() -> u32 {
    state start() {
        let recovered: u32 = parse_like(false) or(failed) {
            if failed {
                exit 42;
            }
            0
        };

        exit recovered;
    }
}

// Tuples can be passed, returned, and compared structurally.
fn pair(value: u32, flag: bool) -> (u32, bool) {
    (value, flag)
}

task main() -> u32 {
    state start() {
        let actual: (u32, bool) = pair(42, true);
        let expected: (u32, bool) = (42, true);

        if actual == expected && actual != (0, false) {
            exit 42;
        }

        exit 0;
    }
}

// observe proves a dynamic index is in bounds before indexing.
task main() -> u32 {
    state start() {
        let values: [u32; 4] = [10, 20, 30, 40];
        let index: u32 = 2;

        observe index < 4 else {
            exit 0;
        }

        exit values[0] + values[index] or(err) 0;
    }
}

// Arrays can contain flattened aggregate values like tuples.
task main() -> u32 {
    state start() {
        let pairs: [(u32, bool); 2] = [(10, false), (42, true)];
        let index: u32 = 1;

        observe index < 2 else {
            exit 0;
        }

        if pairs[index] == (42, true) {
            exit 42;
        }

        exit 0;
    }
}

// for loops over fixed arrays are bounded.
task main() -> u32 {
    state start() {
        let values: [u32; 4] = [9, 10, 11, 12];
        let mut total: u32 = 0;

        for value in values {
            total = total + value or(err) 0;
        }

        exit total;
    }
}

// Ranges are start-inclusive and end-exclusive.
task main() -> u32 {
    state start() {
        let range = 0..7;
        let mut total: u32 = 0;

        for value in range {
            total = total + value or(err) 0;
        }

        exit total * 2 or(err) 0;
    }
}

// go transfers control to another state in the same task.
task main() -> u32 {
    state start() {
        go worker(42);
    }

    state worker(value: u32) {
        exit value;
    }
}

// Cyclic go paths need fresh Event evidence on each loop.
task main() -> u32 {
    state start() {
        go count(0);
    }

    state count(value: u32) {
        if value == 42 {
            exit value;
        }

        unsafe { Event::mark(value); }
        unsafe { Structural::use(value); }
        go count(value + 1 or(err) 0);
    }
}

// go arguments are evaluated before active state arguments are replaced.
task main() -> u32 {
    state start() {
        go swap(7, 42);
    }

    state swap(first: u32, second: u32) {
        if first == 42 {
            exit second;
        } else {
            unsafe { Event::mark(first); }
            unsafe { Structural::use(first); }
            go swap(second, first);
        }
    }
}

// Markers are compile-time facts attached to value places.
marker Trusted();

fn accept(value: u32 with Trusted) -> u32 with Trusted {
    return value;
}

task main() -> u32 {
    state start() {
        let raw: u32 = 42;
        let marked: u32 = raw;
        unsafe { Trusted::mark(marked); }
        let copied: u32 with Trusted = marked;
        exit accept(copied);
    }
}

// Companion rules preserve user marker facts through operators.
marker UpperBound(value: place, bound: place);

mark Sub(a: place, amount: place, result: place) {
    if a with UpperBound(a, ?bound) {
        implies UpperBound(result, bound) for result;
    }
}

fn keep_upper_bound(value: u32 with UpperBound(4)) -> u32 with UpperBound(4) {
    return value;
}

task main() -> u32 {
    state start() {
        let index: u32 = 3;
        unsafe { UpperBound::mark(index, 4); }
        let fallback: u32 = 0;
        unsafe { UpperBound::mark(fallback, 4); }
        let smaller: u32 with UpperBound(4) = index - 1 or(err) fallback;
        exit keep_upper_bound(smaller) + 40 or(err) 0;
    }
}

// Built-in companion rules attach facts to checked operator results.
task main() -> u32 {
    state start() {
        let values: [u32; 4] = [7, 14, 21, 42];
        let raw: u32 = 19;
        let fallback: u32 = 0;
        unsafe { LessThan::mark(fallback, 4); }
        let index: u32 with LessThan(4) = raw % 4 or(err) fallback;

        exit values[index];
    }
}

// Relevant parameters copy by default, so caller and callee each use one place.
fn remember(event: relevant u32) -> () {
    unsafe { Structural::use(event); }
}

task main() -> u32 {
    state start() {
        let event: relevant u32 = 42;
        remember(event);
        unsafe { Structural::use(event); }
        exit 42;
    }
}

// take moves a relevant place into the callee instead of copying it.
fn handle(take event: relevant u32) -> () {
    unsafe { Structural::use(event); }
}

task main() -> u32 {
    state start() {
        let event: relevant u32 = 42;
        handle(event);
        exit 42;
    }
}

// Linear parameters move their argument even without writing take.
fn close(handle: linear u32) -> () {
    unsafe { Structural::consume(handle); }
}

task main() -> u32 {
    state start() {
        let handle: linear u32 = 42;
        close(handle);
        exit 42;
    }
}

// Structural trusted operations discharge place-mode obligations.
task main() -> u32 {
    state start() {
        let event: relevant u32 = 40;
        let handle: linear u32 = 2;

        unsafe { Structural::use(event); }
        unsafe { Structural::consume(handle); }

        exit 42;
    }
}
